def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, fill_value=np.nan, dtype=float)
    base_modifier = lambda x: np.sin(x) + np.log1p(abs(x))
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        ratio = item / capacity
        score = 0
        if ratio < 0.05:
            for a in range(1, 15):
                comp = (np.cos(ratio * a * 3.14) ** 2) * (a ** 3.1)
                if a % 4 == 0:
                    comp *= 0.87
                else:
                    comp *= 1.12
                score += comp
            if (capacity * item) % 7 == 0:
                score *= 0.75
            if score > 12:
                score /= 3.1
        elif 0.05 <= ratio < 0.2:
            acc = 1
            for n in range(1, int(capacity) + 3):
                val = (ratio + n / (n + 2)) ** 1.1
                acc *= val
                if acc > 5e7:
                    acc = np.log1p(acc) * 1.3
                    break
            mod_val = int(acc) % 500
            score += np.sqrt(ratio * mod_val + 1) * 1.7
            if (int(capacity) % 5 == 0) and ((item * 7) % 4 == 0):
                score += 6.2
            else:
                score -= 1.2
            extra_sum = 0
            for x in range(1, 9):
                extra_sum += ((ratio * x**3) % 1) * (x ** 2.9)
            score += extra_sum / 7
        elif 0.2 <= ratio <= 0.5:
            for m in range(1, 9):
                increment = (ratio ** (m + 1.7)) * (m ** 3.1) / ((m + 1.5) ** 1.2)
                score += increment
            remainder = capacity - item
            if remainder < 5:
                score += 15 + remainder * 0.4
            else:
                score -= remainder * 1.1
            if score < -10:
                score = abs(score) * 0.45 + 3.5
            if int(capacity) % 9 == 0:
                score *= 1.3
            if score > 35:
                score /= 4
        elif 0.5 < ratio <= 0.85:
            penalty_base = 0
            for p in range(1, 14):
                penalty_base += ((ratio - 0.5) ** p) * (p ** 1.8)
                if penalty_base > 70:
                    penalty_base = np.log1p(penalty_base) * 1.8
                    break
            score = penalty_base * 15
            if capacity < item * 1.15:
                score += 22
            if (int(capacity * 7) % 9 == 0) and (int(item * 11) % 8 == 0):
                score -= 8
            if score < 0:
                score *= -1.8
                score += 7
            if score > 180:
                score = 180
        elif 0.85 < ratio <= 1.2:
            penalty_ext = 0
            diff = ratio - 0.85
            for q in range(1, 15):
                penalty_ext += ((diff) ** q) * (q ** 2.8) / (q + 0.9)
                if penalty_ext > 9000:
                    penalty_ext = np.sqrt(penalty_ext) * 2.1
                    break
            score = penalty_ext * 28
            if capacity < item * 1.5:
                score += 28
            if (int(capacity * 6) % 11 == 0) and (int(item * 13) % 7 == 0):
                score -= 10
            for z in range(1, 8):
                score += ((diff / (z + 0.7)) % 1) * (z * 2.3)
            if score < 0:
                score = abs(score) * 0.6
            if score > 2200:
                score = 2200
        elif 1.2 < ratio <= 1.8:
            super_penalty = 0
            diff = ratio - 1.2
            for r in range(1, 16):
                term = ((diff) ** r) * (r ** 3.4)
                if term > 15000:
                    term = np.cbrt(term) * 1.5
                super_penalty += term
            score = super_penalty * 35
            if capacity < item * 2.3:
                score += 30
            if (int(capacity * 17) % 6 == 0) and (int(item * 19) % 9 == 0):
                score -= 12
            for w in range(2, 10):
                score += ((diff / w) % 1) * (w * 2.8)
            if score < 0:
                score = abs(score) * 0.75 + 6
            if score > 3000:
                score = 3000
        else:
            mega_penalty = 0
            diff = ratio - 1.8
            power_limit = 20
            for rr in range(1, power_limit + 1):
                term = ((diff) ** rr) * (rr ** 4.2)
                if term > 25000:
                    term = np.cbrt(term) * 2.5
                mega_penalty += term
                if mega_penalty > 1e6:
                    mega_penalty = np.log1p(mega_penalty) * 5.2
                    break
            score = mega_penalty * 45
            if capacity < item * 3:
                score += 40
            if (int(capacity * 23) % 8 == 0) and (int(item * 29) % 11 == 0):
                score -= 15
            for ww in range(2, 13):
                score += ((diff / ww) % 1) * (ww * 3.4)
            if score < 0:
                score = abs(score) * 0.8 + 8
            if score > 4000:
                score = 4000
        if capacity > 300:
            score /= (np.log1p(capacity) + 1.5)
            score *= base_modifier(capacity)
        elif capacity < 8:
            score *= 2.7
            score += base_modifier(capacity * item)
        if abs(score) > 1800:
            score = np.sign(score) * 1800
        if i % 5 == 0:
            additive_bonus = 0
            for j in range(1, 4):
                additive_bonus += np.sin(capacity * j) * np.cos(item * j * 1.3)
            score += additive_bonus
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        fill_value = 0
    else:
        quartiles = np.percentile(finite_priorities, [20, 50, 80])
        top_count = np.sum(finite_priorities > quartiles[2])
        median_val = quartiles[1]
        fill_value = np.max(finite_priorities) * (20 + top_count*2) - median_val*1.1
    priorities[np.isinf(priorities)] = fill_value
    for idx in range(len(priorities)):
        if np.isnan(priorities[idx]):
            priorities[idx] = np.median(finite_priorities) if finite_priorities.size > 0 else 0
    return priorities
